<p>
	text1 text2 text3 text4 text5 text6 text7 text8 text9 text10 text11 text12 <code>.x</code> textabc
</p>

<!-- 101 chars: closing tag stays intact, break falls at the whitespace before the trailing word -->
<p>
	text1 text2 text3 text4 text5 text6 text7 text8 text9 text10 text11 text12 <code>.x</code>
	textabcd
</p>
